firmware_template.source:
#include "touch_capacitive.h"
#include <Arduino.h>
static uint8_t _pin=4;static uint16_t _thresh=40;static uint16_t _val=0;static bool _pressed=false;static unsigned long _l=0;
void touch_setup(uint8_t p,uint16_t t){_pin=p;_thresh=t;Serial.printf("[touch] OK pin=%d thresh=%d\n",p,t);}
void touch_loop(){if(millis()-_l<50)return;_l=millis();_val=touchRead(_pin);_pressed=(_val<_thresh);}
bool touch_pressed(){return _pressed;}
uint16_t touch_get_value(){return _val;}
